{
  "c1": {
    "allegation": "65 records were selectively excluded to improve outcome statistics",
    "evidence": "pipeline log shows the 65 excluded records are HIS-migration duplicates with no clinical data differences",
    "resolution": "standard HIS migration deduplication, not selective exclusion",
    "favors_defense": true
  },
  "c2": {
    "allegation": "co-author dataset differs from the published dataset in a way suggesting manipulation",
    "evidence": "both versions output 847 records from 912 raw records; the 23-record difference is InternalRecordID-only with identical clinical fields",
    "resolution": "ID-selection artefact from newest vs oldest tiebreaker, not a different patient population",
    "favors_defense": true
  },
  "c3": {
    "allegation": "Wang Yisheng's later distancing undermines the paper's integrity",
    "evidence": "Wang Yisheng co-signed before the complaint and ran V2.0 before later distancing under committee pressure",
    "resolution": "contemporaneous co-signature and pipeline authorship are more credible than post-complaint distancing",
    "favors_defense": true
  },
  "c4": {
    "allegation": "Lin Yi acted alone to manipulate the dataset",
    "evidence": "pipeline log shows Wang Yisheng authored V2.0 with the core PatientID + VisitDate deduplication logic",
    "resolution": "critical deduplication logic was co-author documented, not unilateral manipulation by Lin Yi",
    "favors_defense": true
  }
}

